import sys

def main():
    input = sys.stdin.read().split()
    N = int(input[0])
    S = input[1]

    a_seen = b_seen = c_seen = False
    count = 0

    for char in S:
        count += 1
        if char == 'A':
            a_seen = True
        elif char == 'B':
            b_seen = True
        elif char == 'C':
            c_seen = True

        if a_seen and b_seen and c_seen:
            print(count)
            return

if __name__ == "__main__":
    main()
